import yaml, json, anthropic
from pathlib import Path

def load_behavior_spec(path: str) -> dict:
    return yaml.safe_load(Path(path).read_text())

def run_behavior_eval(spec: dict, client: anthropic.Anthropic) -> dict:
    results = []
    for behavior in spec["behaviors"]:
        dataset = json.loads(Path(behavior["eval_dataset"]).read_text())
        passed = 0
        for example in dataset:
            response = client.messages.create(
                model="claude-opus-4-8",
                max_tokens=1024,
                system=example.get("system_prompt", ""),
                messages=[{"role": "user", "content": example["input"]}]
            )
            output = response.content[0].text
            # Check each 'then' assertion
            all_pass = all(
                check_assertion(assertion, output, example)
                for assertion in behavior["then"]
            )
            if all_pass:
                passed += 1
        results.append({
            "behavior_id": behavior["id"],
            "pass_rate": passed / len(dataset),
            "threshold": 0.95,
            "passed": (passed / len(dataset)) >= 0.95,
        })
    return results

def check_assertion(assertion: str, output: str, example: dict) -> bool:
    # Dispatch to assertion handler based on assertion text
    # (simplified — real implementation uses LLM judge or regex)
    if "risk_level = high" in assertion:
        return '"risk_level": "high"' in output
    if "does NOT hallucinate" in assertion:
        return len(output) < 1000  # simplified heuristic
    return True  # default pass for complex assertions needing judge
